import React, { useState, useRef } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';
import { useVehicles } from '../context/VehicleContext';

const ManageVehicles = () => {
  const { vehicles, addVehicle, updateVehicle, deleteVehicle, toggleVehicleStatus } = useVehicles();

  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedVehicles, setSelectedVehicles] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingVehicle, setEditingVehicle] = useState(null);
  const [formData, setFormData] = useState({ name: '', category: '', price: '', status: 'active', image: '' });
  const [imagePreview, setImagePreview] = useState('');
  const fileInputRef = useRef(null);

  const filteredVehicles = vehicles.filter(vehicle => {
    const matchesSearch = vehicle.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = !categoryFilter || vehicle.category.toLowerCase() === categoryFilter.toLowerCase();
    const matchesStatus = !statusFilter || vehicle.status.toLowerCase() === statusFilter.toLowerCase();
    return matchesSearch && matchesCategory && matchesStatus;
  });

  const handleSelectAll = (e) => {
    if (e.target.checked) {
      setSelectedVehicles(filteredVehicles.map(v => v.id));
    } else {
      setSelectedVehicles([]);
    }
  };

  const handleSelectVehicle = (id) => {
    if (selectedVehicles.includes(id)) {
      setSelectedVehicles(selectedVehicles.filter(v => v !== id));
    } else {
      setSelectedVehicles([...selectedVehicles, id]);
    }
  };

  const handleAddVehicleClick = () => {
    setEditingVehicle(null);
    setFormData({ name: '', category: '', price: '', status: 'active', image: '' });
    setImagePreview('');
    setShowModal(true);
  };

  const handleEditVehicle = (vehicle) => {
    setEditingVehicle(vehicle);
    setFormData({ ...vehicle });
    setImagePreview(vehicle.image || '');
    setShowModal(true);
  };

  const handleDeleteVehicle = (id) => {
    deleteVehicle(id);
  };

  const handleToggleStatus = (id) => {
    toggleVehicleStatus(id);
  };

  const handleSaveVehicle = () => {
    if (editingVehicle) {
      updateVehicle(editingVehicle.id, formData);
    } else {
      addVehicle(formData);
    }
    setShowModal(false);
  };

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Handle image file upload and convert to base64
  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      // Validate file type
      const validTypes = ['image/jpeg', 'image/png', 'image/jpg', 'image/gif', 'image/webp'];
      if (!validTypes.includes(file.type)) {
        alert('Please upload a valid image file (JPEG, PNG, JPG, GIF, or WebP)');
        return;
      }

      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        alert('Image size must be less than 5MB');
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result;
        setFormData({ ...formData, image: base64String });
        setImagePreview(base64String);
      };
      reader.onerror = () => {
        alert('Error reading file. Please try again.');
      };
      reader.readAsDataURL(file);
    }
  };

  const removeImage = () => {
    setFormData({ ...formData, image: '' });
    setImagePreview('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const totalVehicles = vehicles.length;
  const activeVehicles = vehicles.filter(v => v.status === 'active').length;
  const inactiveVehicles = vehicles.filter(v => v.status === 'inactive').length;

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Manage Vehicles</h2>

          {/* Top Info Cards */}
          <div style={styles.topInfoCards} aria-label="Key vehicle and bookings summary">
            <div style={styles.infoCard} aria-label={`${totalVehicles} Total Vehicles`}>
              <div style={styles.iconContainer}>
                <svg viewBox="0 0 24 24" stroke="#329b4a" fill="none" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={styles.iconSvg}>
                  <path d="M3 10h18v7a3 3 0 0 1-3 3H6a3 3 0 0 1-3-3v-7Z"/>
                  <path d="M3 10V7a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4v3"/>
                </svg>
              </div>
              <div style={styles.infoText}>
                <span style={styles.infoNumber}>{totalVehicles}</span> Total Vehicles
              </div>
            </div>
            <div style={{...styles.infoCard, ...styles.infoCardActive}} aria-label={`${activeVehicles} Active Vehicles`}>
              <div style={{...styles.iconContainer, backgroundColor: '#6bbb6f'}}>
                <svg viewBox="0 0 24 24" stroke="#329b4a" fill="none" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={styles.iconSvg}>
                  <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/>
                  <polyline points="22 4 12 14.01 9 11.01"/>
                </svg>
              </div>
              <div style={styles.infoText}>
                <span style={{...styles.infoNumber, color: '#6bbb6f'}}>{activeVehicles}</span> Active Vehicles
              </div>
            </div>
            <div style={{...styles.infoCard, ...styles.infoCardInactive}} aria-label={`${inactiveVehicles} Inactive Vehicles`}>
              <div style={{...styles.iconContainer, backgroundColor: '#cb3b17'}}>
                <svg viewBox="0 0 24 24" stroke="#cb3b17" fill="none" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={styles.iconSvg}>
                  <circle cx="12" cy="12" r="10"/>
                  <line x1="15" y1="9" x2="9" y2="15"/>
                  <line x1="9" y1="9" x2="15" y2="15"/>
                </svg>
              </div>
              <div style={styles.infoText}>
                <span style={{...styles.infoNumber, color: '#cb3b17'}}>{inactiveVehicles}</span> Inactive Vehicles
              </div>
            </div>
          </div>

          {/* Add Vehicle Button */}
          <button style={styles.addBtn} onClick={handleAddVehicleClick} aria-label="Add new vehicle">+ Add Vehicle</button>

          {/* Filters */}
          <div style={styles.filters} aria-label="Vehicle filters and search inputs">
            <div style={styles.filterGroup}>
              <label htmlFor="carType" style={styles.srOnly}>Filter by Car Type</label>
              <select 
                id="carType" 
                value={categoryFilter} 
                onChange={(e) => setCategoryFilter(e.target.value)}
                style={styles.select}
              >
                <option value="">Car Type</option>
                <option value="sedan">Sedan</option>
                <option value="suv">SUV</option>
                <option value="van">Van</option>
                <option value="luxury">Luxury</option>
              </select>
            </div>
            <div style={styles.filterGroup}>
              <label htmlFor="statusFilter" style={styles.srOnly}>Filter by Status</label>
              <select 
                id="statusFilter" 
                value={statusFilter} 
                onChange={(e) => setStatusFilter(e.target.value)}
                style={styles.select}
              >
                <option value="">Status</option>
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
              </select>
            </div>
            <div style={{...styles.filterGroup, flex: '1 1 250px'}}>
              <label htmlFor="searchInput" style={styles.srOnly}>Search Vehicles</label>
              <input 
                type="search" 
                id="searchInput"
                placeholder="Search..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={styles.searchInput}
              />
            </div>
          </div>

          {/* Table */}
          <div style={styles.tableContainer}>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th style={{...styles.th, ...styles.checkboxCell}}>
                    <input 
                      type="checkbox" 
                      checked={selectedVehicles.length === filteredVehicles.length && filteredVehicles.length > 0}
                      onChange={handleSelectAll}
                      aria-label="Select all vehicles"
                    />
                  </th>
                  <th style={styles.th}>Photos</th>
                  <th style={styles.th}>Car</th>
                  <th style={styles.th}>Category</th>
                  <th style={styles.th}>Daily Rate</th>
                  <th style={styles.th}>Status</th>
                  <th style={{...styles.th, ...styles.actionsCell}}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredVehicles.length === 0 ? (
                  <tr>
                    <td colSpan="7" style={{...styles.td, textAlign: 'center', padding: '40px'}}>
                      No vehicles found. Click "+ Add Vehicle" to add one.
                    </td>
                  </tr>
                ) : (
                  filteredVehicles.map(vehicle => (
                    <tr key={vehicle.id} style={styles.tr}>
                      <td style={{...styles.td, ...styles.checkboxCell}}>
                        <input 
                          type="checkbox" 
                          checked={selectedVehicles.includes(vehicle.id)}
                          onChange={() => handleSelectVehicle(vehicle.id)}
                          aria-label={`Select ${vehicle.name}`}
                        />
                      </td>
                      <td style={{...styles.td, ...styles.photosCell}}>
                        <img src={vehicle.image || 'https://via.placeholder.com/150'} alt={vehicle.name} style={styles.carImage} />
                      </td>
                      <td style={{...styles.td, ...styles.carName}}>{vehicle.name}</td>
                      <td style={{...styles.td, ...styles.category}}>{vehicle.category}</td>
                      <td style={{...styles.td, ...styles.dailyRate}}>₱{vehicle.price}</td>
                      <td style={{...styles.td, ...styles.statusCell}}>
                        <span style={{
                          ...styles.statusBadge,
                          ...(vehicle.status === 'active' ? styles.statusActive : styles.statusInactive)
                        }}>
                          {vehicle.status}
                        </span>
                      </td>
                      <td style={{...styles.td, ...styles.actionsCell}}>
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleEditVehicle(vehicle)}
                          aria-label={`Edit ${vehicle.name}`}
                        >
                          ✏️
                        </button>
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleToggleStatus(vehicle.id)}
                          aria-label={`Toggle status for ${vehicle.name}`}
                        >
                          {vehicle.status === 'active' ? '⏸️' : '▶️'}
                        </button>
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleDeleteVehicle(vehicle.id)}
                          aria-label={`Delete ${vehicle.name}`}
                        >
                          🗑️
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Vehicle rental benefits">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16"/>
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
                <path d="M15 15h20" />
                <path d="M12 38h10" />
                <path d="M33 38h7" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
                <line x1="0" y1="7" x2="22" y2="7" />
                <line x1="4" y1="12" x2="18" y2="12" />
                <line x1="7" y1="16" x2="15" y2="16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and Hassle free online reservations</span>
              </div>
            </div>
          </section>
        </div>
      </main>

      {/* Modal */}
      {showModal && (
        <div style={styles.modalOverlay} onClick={() => setShowModal(false)}>
          <div style={styles.modal} onClick={e => e.stopPropagation()}>
            <h3 style={styles.modalTitle}>{editingVehicle ? 'Edit Vehicle' : 'Add New Vehicle'}</h3>
            <form onSubmit={(e) => { e.preventDefault(); handleSaveVehicle(); }}>
              <div style={styles.formGroup}>
                <label style={styles.label}>Car Name</label>
                <input 
                  type="text" 
                  name="name" 
                  value={formData.name} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Category</label>
                <select 
                  name="category" 
                  value={formData.category} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                >
                  <option value="">Select Category</option>
                  <option value="Sedan">Sedan</option>
                  <option value="SUV">SUV</option>
                  <option value="Van">Van</option>
                  <option value="Luxury">Luxury</option>
                </select>
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Daily Rate (₱)</label>
                <input 
                  type="number" 
                  name="price" 
                  value={formData.price} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Status</label>
                <select 
                  name="status" 
                  value={formData.status} 
                  onChange={handleInputChange}
                  style={styles.input}
                >
                  <option value="active">Active</option>
                  <option value="inactive">Inactive</option>
                </select>
              </div>
              
              {/* Image Upload */}
              <div style={styles.formGroup}>
                <label style={styles.label}>Vehicle Image (JPEG, PNG, JPG, GIF, WebP - Max 5MB)</label>
                <input 
                  type="file" 
                  ref={fileInputRef}
                  accept="image/jpeg,image/png,image/jpg,image/gif,image/webp"
                  onChange={handleImageUpload}
                  style={styles.fileInput}
                />
                {imagePreview && (
                  <div style={styles.imagePreviewContainer}>
                    <img src={imagePreview} alt="Preview" style={styles.imagePreview} />
                    <button 
                      type="button" 
                      onClick={removeImage}
                      style={styles.removeImageBtn}
                    >
                      ×
                    </button>
                  </div>
                )}
              </div>

              <div style={styles.modalButtons}>
                <button type="button" onClick={() => setShowModal(false)} style={styles.cancelBtn}>Cancel</button>
                <button type="submit" style={styles.saveBtn}>Save</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inria+Serif&display=swap');
        
        * { box-sizing: border-box; }
        
        .sr-only {
          position: absolute !important;
          width: 1px !important;
          height: 1px !important;
          padding: 0 !important;
          margin: -1px !important;
          overflow: hidden !important;
          clip: rect(0,0,0,0) !important;
          border: 0 !important;
        }
      `}</style>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    minHeight: '100vh',
    backgroundColor: '#e8f2f2',
    fontFamily: 'Inria Serif, serif',
  },
  mainContent: {
    flex: 1,
    marginLeft: '250px',
    marginTop: '60px',
    padding: '20px',
  },
  contentWrapper: {
    maxWidth: '1040px',
    margin: '0 auto',
  },
  pageTitle: {
    fontSize: '22px',
    fontWeight: '700',
    marginBottom: '14px',
    fontFamily: 'Inria Serif, serif',
  },
  topInfoCards: {
    display: 'flex',
    gap: '14px',
    marginBottom: '18px',
  },
  infoCard: {
    flex: '1 1 0',
    background: 'white',
    padding: '14px 18px',
    borderRadius: '8px',
    display: 'flex',
    alignItems: 'center',
    gap: '11px',
    boxShadow: '1.5px 2px 11px rgb(129 158 219 / 0.16)',
  },
  infoCardActive: {},
  infoCardInactive: {},
  iconContainer: {
    flexShrink: 0,
    width: '32px',
    height: '32px',
    backgroundColor: '#d0e9de',
    borderRadius: '45%',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  iconSvg: {
    width: '18px',
    height: '18px',
  },
  infoText: {
    fontWeight: 600,
    whiteSpace: 'nowrap',
    fontSize: '14px',
  },
  infoNumber: {
    fontWeight: 700,
    color: '#282d35',
    fontSize: '18px',
  },
  addBtn: {
    backgroundColor: '#237643',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    fontWeight: 700,
    padding: '11px 22px',
    fontSize: '14px',
    cursor: 'pointer',
    float: 'right',
    marginBottom: '14px',
    fontFamily: 'Inria Serif, serif',
  },
  filters: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '12px',
    marginBottom: '18px',
    alignItems: 'center',
  },
  filterGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '5px',
  },
  select: {
    background: 'white',
    borderRadius: '8px',
    border: '1.5px solid #6c819f',
    fontWeight: 600,
    fontSize: '13.8px',
    padding: '7px 11px',
    minWidth: '120px',
    color: '#404040',
    fontFamily: 'Inria Serif, serif',
  },
  searchInput: {
    background: 'white',
    borderRadius: '8px',
    border: '1.5px solid #6c819f',
    fontWeight: 600,
    fontSize: '13.8px',
    padding: '7px 11px',
    minWidth: '120px',
    color: '#404040',
    fontFamily: 'Inria Serif, serif',
    width: '100%',
  },
  srOnly: {
    position: 'absolute',
    width: '1px',
    height: '1px',
    padding: '0',
    margin: '-1px',
    overflow: 'hidden',
    clip: 'rect(0,0,0,0)',
    border: '0',
  },
  tableContainer: {
    overflowX: 'auto',
    boxShadow: '1px 3px 8px rgb(129 158 219 / 0.16)',
    borderRadius: '14px',
    background: '#fff',
  },
  table: {
    borderCollapse: 'collapse',
    width: '100%',
    tableLayout: 'fixed',
    fontSize: '15px',
    fontWeight: 600,
    fontFamily: 'Inria Serif, serif',
  },
  th: {
    whiteSpace: 'nowrap',
    padding: '15px 15px',
    color: '#414a84',
    textAlign: 'left',
    borderBottom: '2.4px solid #3967cb',
    backgroundColor: '#e1eaff',
  },
  td: {
    whiteSpace: 'nowrap',
    padding: '14px 15px',
    verticalAlign: 'middle',
    color: '#414a84',
    borderBottom: '1.5px solid #ddd',
  },
  tr: {
    borderBottom: '1.5px solid #ddd',
  },
  checkboxCell: {
    textAlign: 'center',
    width: '40px',
  },
  photosCell: {},
  carImage: {
    width: '82px',
    height: '46px',
    borderRadius: '8px',
    objectFit: 'cover',
  },
  carName: {
    fontWeight: 700,
    color: '#000b8e',
  },
  category: {
    color: '#4652c4',
  },
  dailyRate: {
    fontWeight: 700,
    color: '#00ab00',
  },
  statusCell: {
    textAlign: 'center',
  },
  statusBadge: {
    padding: '7px 16px',
    borderRadius: '12px',
    fontWeight: 700,
    fontSize: '13px',
    cursor: 'default',
    whiteSpace: 'nowrap',
    display: 'inline-block',
  },
  statusActive: {
    backgroundColor: '#34871e',
    color: 'white',
  },
  statusInactive: {
    backgroundColor: '#cb3b17',
    color: 'white',
  },
  actionsCell: {
    textAlign: 'right',
    width: '120px',
  },
  actionBtn: {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    fontSize: '16px',
    padding: '5px',
    margin: '0 2px',
  },
  infoRow: {
    marginTop: '34px',
    display: 'flex',
    justifyContent: 'space-between',
    background: 'white',
    borderRadius: '10px',
    boxShadow: '0 2px 5px #c4c9db',
    padding: '19px 28px',
    maxWidth: '100%',
  },
  infoBox: {
    display: 'flex',
    gap: '14px',
    maxWidth: '33%',
  },
  infoSvg: {
    width: '48px',
    height: '48px',
    stroke: '#222',
  },
  infoText: {
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
  },
  modalOverlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0,0,0,0.5)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 2000,
  },
  modal: {
    background: 'white',
    borderRadius: '12px',
    padding: '24px',
    width: '90%',
    maxWidth: '500px',
    maxHeight: '90vh',
    overflowY: 'auto',
  },
  modalTitle: {
    marginTop: 0,
    marginBottom: '20px',
    fontSize: '20px',
    fontWeight: '700',
    fontFamily: 'Inria Serif, serif',
  },
  formGroup: {
    marginBottom: '16px',
  },
  label: {
    display: 'block',
    marginBottom: '6px',
    fontWeight: 600,
    fontSize: '14px',
    fontFamily: 'Inria Serif, serif',
  },
  input: {
    width: '100%',
    padding: '10px 12px',
    borderRadius: '8px',
    border: '1.5px solid #6c819f',
    fontSize: '14px',
    fontFamily: 'Inria Serif, serif',
  },
  fileInput: {
    width: '100%',
    padding: '10px 12px',
    borderRadius: '8px',
    border: '1.5px solid #6c819f',
    fontSize: '14px',
    fontFamily: 'Inria Serif, serif',
    backgroundColor: '#fff',
  },
  imagePreviewContainer: {
    position: 'relative',
    marginTop: '10px',
    display: 'inline-block',
  },
